 101→    private void updateNotificationBuilder(@Nullable PostImmutableModel post) {
 102→        // set the Notification's title and prepare the Notifications message text, i.e. "1/3 Posts, 4/17 media items"
 103→        if (sNotificationData.mTotalMediaItems > 0 && sNotificationData.mTotalPostItems == 0) {
 104→            // only media items are being uploaded
 105→            // check if special case for ONE media item
 106→            if (sNotificationData.mTotalMediaItems == 1) {
 107→                mNotificationBuilder.setContentTitle(buildNotificationTitleForMedia());
 108→                mNotificationBuilder.setContentText(buildNotificationSubtitleForMedia());
 109→            } else {
 110→                mNotificationBuilder.setContentTitle(buildNotificationTitleForMixedContent());
 111→                mNotificationBuilder.setContentText(buildNotificationSubtitleForMedia());
 112→            }
 113→        } else if (sNotificationData.mTotalMediaItems == 0 && sNotificationData.mTotalPostItems > 0) {
 114→            // only Post / Pages are being uploaded
 115→            // check if special case for ONE Post
 116→            if (sNotificationData.mTotalPostItems == 1) {
 117→                mNotificationBuilder.setContentTitle(buildNotificationTitleForPost(post));
 118→                mNotificationBuilder.setContentText(buildNotificationSubtitleForPost(post));
 119→            } else {
 120→                mNotificationBuilder.setContentTitle(buildNotificationTitleForMixedContent());
 121→                mNotificationBuilder.setContentText(buildNotificationSubtitleForPosts());
 122→            }
 123→        } else {
 124→            // mixed content (Post/Pages and media) is being uploaded
 125→            mNotificationBuilder.setContentTitle(buildNotificationTitleForMixedContent());
 126→            mNotificationBuilder.setContentText(buildNotificationSubtitleForMixedContent());
 127→        }
 128→    }
