 130→    private synchronized void startOrUpdateForegroundNotification(@Nullable PostImmutableModel post) {
 131→        boolean isTotalPostsAndMediaItemsCountZero = sNotificationData.mTotalPostItems == 0
 132→                                                     && sNotificationData.mTotalMediaItems == 0;
 133→        if (isTotalPostsAndMediaItemsCountZero) {
 134→            return;
 135→        }
 136→        updateNotificationBuilder(post);
 137→        if (sNotificationData.mNotificationId == 0) {
 138→            sNotificationData.mNotificationId = (new Random()).nextInt();
 139→            try {
 140→                mService.startForeground(sNotificationData.mNotificationId, mNotificationBuilder.build());
 141→            } catch (RuntimeException exception) {
 142→                AppLog.e(T.POSTS, "startOrUpdateForegroundNotification failed; See issue #18714", exception);
 143→            }
 144→        } else {
 145→            // service was already started, let's just modify the notification
 146→            doNotify(sNotificationData.mNotificationId, mNotificationBuilder.build(), null);
 147→        }
