 216→    void incrementUploadedPostCountFromForegroundNotification(@NonNull PostImmutableModel post, boolean force) {
 217→        // first we need to check that we only count this post once as "ended" (either successfully or with error)
 218→        // for every error we get. We'll then try to increment the Post count as it's been cancelled/failed because the
 219→        // related media was cancelled or has failed too (i.e. we can't upload a Post with failed media, therefore
 220→        // it needs to be cancelled).
 221→        if (!force && isPostAlreadyInPostCount(post)) {
 222→            return;
 223→        } else {
 224→            addPostToPostCount(post);
 225→        }
 226→        sNotificationData.mCurrentPostItem++;
 227→
 228→        // update Notification now
 229→        if (!removeNotificationAndStopForegroundServiceIfNoItemsInQueue()) {
 230→            updateForegroundNotification(post);
 231→        }
 232→    }
