 242→    private boolean removeNotificationAndStopForegroundServiceIfNoItemsInQueue() {
 243→        if (sNotificationData.mCurrentPostItem == sNotificationData.mTotalPostItems
 244→            && sNotificationData.mCurrentMediaItem == sNotificationData.mTotalMediaItems) {
 245→            mNotificationManager.cancel(sNotificationData.mNotificationId);
 246→            // reset the notification id so a new one is generated next time the service is started
 247→            sNotificationData.mNotificationId = 0;
 248→            resetNotificationCounters();
 249→            mService.stopForeground(true);
 250→            return true;
 251→        }
 252→        return false;
 253→    }
