 296→    void updateNotificationSuccessForPost(@NonNull PostImmutableModel post, @NonNull SiteModel site,
 297→                                          boolean isFirstTimePublish) {
 298→        if (!WordPress.Companion.getAppIsInTheBackground()) {
 299→            // only produce success notifications for the user if the app is in the background
 300→            return;
 301→        }
 302→        AppLog.d(AppLog.T.POSTS, "updateNotificationSuccessForPost");
 303→
 304→        // Get the shareableUrl
 305→        String shareableUrl = WPMeShortlinks.getPostShortlink(site, post);
 306→        if (shareableUrl == null && !TextUtils.isEmpty(post.getLink())) {
 307→            shareableUrl = post.getLink();
 308→        }
 309→
 310→        // Notification builder
 311→        NotificationCompat.Builder notificationBuilder =
 312→                new NotificationCompat.Builder(mContext.getApplicationContext(),
 313→                        mContext.getString(R.string.notification_channel_normal_id));
 314→        String notificationTitle;
 315→        String notificationMessage;
 316→
 317→        String postTitle = TextUtils.isEmpty(post.getTitle()) ? mContext.getString(R.string.untitled) : post.getTitle();
 318→        notificationTitle = "\"" + postTitle + "\" ";
 319→        notificationMessage = site.getName();
 320→
 321→        PostStatus status = PostStatus.fromPost(post);
 322→        switch (status) {
 323→            case DRAFT:
 324→                notificationTitle += mContext.getString(R.string.draft_uploaded);
 325→                break;
 326→            case SCHEDULED:
 327→                notificationTitle += mContext.getString(
 328→                        post.isPage() ? R.string.page_scheduled : R.string.post_scheduled);
 329→                break;
 330→            case PUBLISHED:
 331→                if (post.isPage()) {
 332→                    notificationTitle += mContext.getString(
 333→                            isFirstTimePublish ? R.string.page_published : R.string.page_updated);
 334→                } else {
 335→                    notificationTitle += mContext.getString(
 336→                            isFirstTimePublish ? R.string.post_published : R.string.post_updated);
 337→                }
 338→                break;
 339→            default:
 340→                notificationTitle += mContext.getString(post.isPage() ? R.string.page_updated : R.string.post_updated);
 341→                break;
 342→        }
 343→
 344→        notificationBuilder.setSmallIcon(R.drawable.ic_app_white_24dp);
 345→        notificationBuilder.setColor(mContext.getResources().getColor(R.color.primary_50));
 346→
 347→        notificationBuilder.setContentTitle(notificationTitle);
 348→        notificationBuilder.setContentText(notificationMessage);
 349→        notificationBuilder.setStyle(new NotificationCompat.BigTextStyle().bigText(notificationMessage));
 350→        notificationBuilder.setOnlyAlertOnce(true);
 351→        notificationBuilder.setAutoCancel(true);
 352→        long notificationId = getNotificationIdForPost(post);
