 359→        Intent notificationIntent = getNotificationIntent(post, site);
 360→        notificationIntent.putExtra(ARG_NOTIFICATION_TYPE, notificationType);
 361→
 362→        PendingIntent pendingIntentPost = PendingIntent.getActivity(
 363→                mContext,
 364→                (int) notificationId,
 365→                notificationIntent,
 366→                PendingIntent.FLAG_ONE_SHOT | PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE
 367→        );
 368→        notificationBuilder.setContentIntent(pendingIntentPost);
 369→
 370→        // Share intent - started if the user tap the share link button - only if the link exist
 371→        if (shareableUrl != null && PostStatus.fromPost(post) == PostStatus.PUBLISHED) {
