 821→    private void updateNotificationProgress() {
 822→        if (sNotificationData.mTotalMediaItems == 0 && sNotificationData.mTotalPostItems == 0) {
 823→            return;
 824→        }
 825→
 826→        mNotificationBuilder.setProgress(100, (int) Math.ceil(getCurrentOverallProgress() * 100), false);
 827→        doNotify(sNotificationData.mNotificationId, mNotificationBuilder.build(), null);
 828→    }
