 834→    private float getCurrentOverallProgress() {
 835→        int totalItemCount = sNotificationData.mTotalPostItems + sNotificationData.mTotalMediaItems;
 836→        float currentMediaProgress = getCurrentMediaProgress();
 837→        float overAllProgress;
 838→        overAllProgress = sNotificationData.mTotalPostItems > 0
 839→                ? (sNotificationData.mCurrentPostItem / sNotificationData.mTotalPostItems) * totalItemCount : 0;
 840→        overAllProgress += sNotificationData.mTotalMediaItems > 0
 841→                ? (sNotificationData.mCurrentMediaItem / sNotificationData.mTotalMediaItems) * totalItemCount : 0;
 842→        overAllProgress += currentMediaProgress;
 843→        return overAllProgress;
 844→    }
 845→
 846→    private float getCurrentMediaProgress() {
 847→        float currentMediaProgress = 0.0f;
 848→        int size = sNotificationData.mediaItemToProgressMap.size();
 849→        for (int i = 0; i < size; i++) {
 850→            int key = sNotificationData.mediaItemToProgressMap.keyAt(i);
 851→            float itemProgress = sNotificationData.mediaItemToProgressMap.get(key);
 852→            currentMediaProgress += (itemProgress / size);
 853→        }
 854→        return currentMediaProgress;
 855→    }
