 462→    public static long getNotificationIdForPost(PostImmutableModel post) {
 463→        long postIdToUse = post.getRemotePostId();
 464→        if (post.isLocalDraft()) {
 465→            postIdToUse = post.getId();
 466→            // Note: local drafts just don't have a remote post Id set yet, so they are all 0. Because of this, we only
 467→            // use the local id for local drafts.
 468→            // there could be the case where a local draft on the device, and a remote post, can get the same ID,
 469→            // since the ID is returned from 2 different sources. In theory this is true, but however the chances are
 470→            // too low so it seems it should work in practically 100% of times.
 471→        }
 472→        // We can't use the local table post id here because it can change between first post (local draft) to
 473→        // first edit (post pulled from the server)
 474→        // but, if this is a local draft, we don't have a choice but to use the local id.
 475→        // otherwise, remote ID is always 0 for any local draft, and this means we'd be providing the same
 476→        // notificationId for 2 different local drafts for the same site, with this ending in the latest notification
 477→        // "stepping" on the first one (the user would always get to see the latest failed local draft, but wouldn't get
 478→        // a notice about the previous ones).
 479→        return post.getLocalSiteId() + postIdToUse;
 480→    }
