 646→    private String buildErrorMessageMixed(int overrideMediaNotUploadedCount) {
 647→        // first we build a summary of what failed and what went OK, like this:
 648→        // i.e. "1 post, with 3 media files not uploaded (9 successfully uploaded)"
 649→        String newErrorMessage = "";
 650→        int postItemsNotUploaded = sNotificationData.mTotalPostItems > 0
 651→                ? sNotificationData.mTotalPostItems - getCurrentPostItem() : 0;
 652→        int mediaItemsNotUploaded = overrideMediaNotUploadedCount > 0
 653→                ? overrideMediaNotUploadedCount : sNotificationData.mTotalMediaItems - getCurrentMediaItem();
 654→
 655→        if (postItemsNotUploaded > 0 && mediaItemsNotUploaded > 0) {
 656→            switch (getPagesAndOrPostsType(postItemsNotUploaded)) {
 657→                case POST:
 658→                    newErrorMessage = (mediaItemsNotUploaded == 1
 659→                            ? mContext.getString(R.string.media_file_post_singular_mixed_not_uploaded_one_file)
 660→                            : String.format(
 661→                                    mContext.getString(
 662→                                            R.string.media_file_post_singular_mixed_not_uploaded_files_plural),
 663→                                    mediaItemsNotUploaded));
 664→                    break;
 665→                case PAGE:
 666→                    newErrorMessage = (mediaItemsNotUploaded == 1
 667→                            ? mContext.getString(R.string.media_file_page_singular_mixed_not_uploaded_one_file)
 668→                            : String.format(
 669→                                    mContext.getString(
 670→                                            R.string.media_file_page_singular_mixed_not_uploaded_files_plural),
 671→                                    mediaItemsNotUploaded));
 672→                    break;
 673→                case PAGES:
 674→                    newErrorMessage = (mediaItemsNotUploaded == 1
 675→                            ? String.format(
 676→                            mContext.getString(R.string.media_file_pages_plural_mixed_not_uploaded_one_file),
 677→                            postItemsNotUploaded)
 678→                            : String.format(
 679→                                    mContext.getString(
 680→                                            R.string.media_file_pages_plural_mixed_not_uploaded_files_plural),
 681→                                    postItemsNotUploaded,
 682→                                    mediaItemsNotUploaded));
 683→                    break;
 684→                case PAGES_OR_POSTS:
 685→                    newErrorMessage = (mediaItemsNotUploaded == 1
 686→                            ? String.format(
 687→                            mContext.getString(R.string.media_file_pages_and_posts_mixed_not_uploaded_one_file),
 688→                            postItemsNotUploaded)
 689→                            : String.format(
 690→                                    mContext.getString(
 691→                                            R.string.media_file_pages_and_posts_mixed_not_uploaded_files_plural),
 692→                                    postItemsNotUploaded,
 693→                                    mediaItemsNotUploaded));
 694→                    break;
 695→                case POSTS:
 696→                default:
 697→                    newErrorMessage = (mediaItemsNotUploaded == 1
 698→                            ? String.format(
 699→                            mContext.getString(R.string.media_file_posts_plural_mixed_not_uploaded_one_file),
 700→                            postItemsNotUploaded)
 701→                            : String.format(
 702→                                    mContext.getString(
 703→                                            R.string.media_file_posts_plural_mixed_not_uploaded_files_plural),
 704→                                    postItemsNotUploaded,
 705→                                    mediaItemsNotUploaded));
 706→                    break;
 707→            }
 708→        } else if (postItemsNotUploaded > 0) {
 709→            switch (getPagesAndOrPostsType(postItemsNotUploaded)) {
 710→                case POST:
 711→                    newErrorMessage = mContext.getString(R.string.media_file_post_singular_only_not_uploaded);
 712→                    break;
 713→                case PAGE:
 714→                    newErrorMessage = mContext.getString(R.string.media_file_page_singular_only_not_uploaded);
 715→                    break;
 716→                case PAGES:
 717→                    newErrorMessage = String.format(
 718→                            mContext.getString(R.string.media_file_pages_plural_only_not_uploaded),
 719→                            postItemsNotUploaded);
 720→                    break;
 721→                case PAGES_OR_POSTS:
 722→                    newErrorMessage = String.format(
 723→                            mContext.getString(R.string.media_file_pages_and_posts_only_not_uploaded),
 724→                            postItemsNotUploaded);
 725→                    break;
 726→                case POSTS:
 727→                default:
 728→                    newErrorMessage = String.format(
 729→                            mContext.getString(R.string.media_file_posts_plural_only_not_uploaded),
 730→                            postItemsNotUploaded);
 731→                    break;
 732→            }
 733→        } else if (mediaItemsNotUploaded > 0) {
 734→            if (mediaItemsNotUploaded == 1) {
 735→                newErrorMessage = mContext.getString(R.string.media_file_not_uploaded);
 736→            } else {
 737→                newErrorMessage =
 738→                        String.format(mContext.getString(R.string.media_files_not_uploaded), mediaItemsNotUploaded);
