 805→    void updateNotificationProgressForMedia(MediaModel media, float progress) {
 806→        if (sNotificationData.mTotalMediaItems == 0 && sNotificationData.mTotalPostItems == 0) {
 807→            return;
 808→        }
 809→
 810→        // only update if media item is in our map - this check is performed because
 811→        // it could happen that a media item is already done uploading but we receive an upload
 812→        // progress event from FluxC after that. We just need to avoid re-adding the item to the map.
 813→        Float currentProgress = sNotificationData.mediaItemToProgressMap.get(media.getId());
 814→        // also, only set updates in increments of 5% per media item to avoid lots of notification updates
 815→        if (currentProgress != null && progress > (currentProgress + 0.05f)) {
 816→            setProgressForMediaItem(media.getId(), progress);
 817→            updateNotificationProgress();
 818→        }
 819→    }
